1	import { renderHook, waitFor } from '@testing-library/react';
2	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
3	import { vi, describe, it, expect, beforeEach } from 'vitest';
4	import React from 'react';
5	import { useHealth } from './useHealth.js';
6	
7	function makeWrapper(queryClient: QueryClient) {
8	  return function Wrapper({ children }: { children: React.ReactNode }) {
9	    return React.createElement(QueryClientProvider, { client: queryClient }, children);
10	  };
11	}
12	
13	function makeQueryClient() {
14	  return new QueryClient({ defaultOptions: { queries: { retry: false } } });
15	}
16	
17	function makeMockFetch(response: unknown, ok = true) {
18	  return vi.fn().mockResolvedValue({
19	    ok,
20	    json: () => Promise.resolve(response),
21	  });
22	}
23	
24	beforeEach(() => {
25	  vi.unstubAllGlobals();
26	});
27	
28	describe('useHealth', () => {
29	  it('returns data and isError=false on success', async () => {
30	    const mockFetch = makeMockFetch({ status: 'ok', fibaro: 'reachable' });
31	    vi.stubGlobal('fetch', mockFetch);
32	
33	    const queryClient = makeQueryClient();
34	    const { result } = renderHook(() => useHealth(), { wrapper: makeWrapper(queryClient) });
35	
36	    await waitFor(() => expect(result.current.isSuccess).toBe(true));
37	    expect(result.current.data).toEqual({ status: 'ok', fibaro: 'reachable' });
38	    expect(result.current.isError).toBe(false);
39	  });
40	
41	  it('returns degraded data and isError=false on degraded status', async () => {
42	    const mockFetch = makeMockFetch({ status: 'degraded', fibaro: 'unreachable' }, false);
43	    vi.stubGlobal('fetch', mockFetch);
44	
45	    const queryClient = makeQueryClient();
46	    const { result } = renderHook(() => useHealth(), { wrapper: makeWrapper(queryClient) });
47	
48	    await waitFor(() => expect(result.current.isSuccess).toBe(true));
49	    expect(result.current.data).toEqual({ status: 'degraded', fibaro: 'unreachable' });
50	    expect(result.current.isError).toBe(false);
51	  });
52	
53	  it('returns degraded data when server returns 503 with valid JSON body', async () => {
54	    const mockFetch = vi.fn().mockResolvedValue({
55	      ok: false,
56	      status: 503,
57	      json: () => Promise.resolve({ status: 'degraded', fibaro: 'unreachable' }),
58	    });
59	    vi.stubGlobal('fetch', mockFetch);
60	
61	    const queryClient = makeQueryClient();
62	    const { result } = renderHook(() => useHealth(), { wrapper: makeWrapper(queryClient) });
63	
64	    await waitFor(() => expect(result.current.isSuccess).toBe(true));
65	    expect(result.current.data).toEqual({ status: 'degraded', fibaro: 'unreachable' });
66	    expect(result.current.isError).toBe(false);
67	  });
68	
69	  it('sets isError=true on network failure', async () => {
70	    const mockFetch = vi.fn().mockRejectedValue(new Error('Network error'));
71	    vi.stubGlobal('fetch', mockFetch);
72	
73	    const queryClient = makeQueryClient();
74	    const { result } = renderHook(() => useHealth(), { wrapper: makeWrapper(queryClient) });
75	
76	    await waitFor(() => expect(result.current.isError).toBe(true));
77	    expect(result.current.data).toBeUndefined();
78	  });
79	
80	  it('calls fetch with /api/health and no Authorization header', async () => {
81	    const mockFetch = makeMockFetch({ status: 'ok', fibaro: 'reachable' });
82	    vi.stubGlobal('fetch', mockFetch);
83	
84	    const queryClient = makeQueryClient();
85	    renderHook(() => useHealth(), { wrapper: makeWrapper(queryClient) });
86	
87	    await waitFor(() => expect(mockFetch).toHaveBeenCalled());
88	
89	    const [url, options] = mockFetch.mock.calls[0] as [string, RequestInit | undefined];
90	    expect(url).toBe('/api/health');
91	    const headers = options?.headers as Record<string, string> | undefined;
92	    expect(headers?.['Authorization']).toBeUndefined();
93	  });
94	
95	  it('sets isError=true when response is not ok (non-JSON HTTP error)', async () => {
96	    const mockFetch = vi.fn().mockResolvedValue({
97	      ok: false,
